// ==UserScript==
// @name         LeprosyVaccine
// @namespace     https://horochan.ru/
// @version      3.2.1
// @description  Скрытие VIP-постов на horochan.ru с настраиваемым плавающим меню. Через CSS :has() — переживает Svelte и виртуальный скроллинг
// @author       You
// @match        *://horochan.ru/*
// @match        *://*.horochan.ru/*
// @icon         data:image/png;base64,
// @grant        none
// ==/UserScript==

(function() {
    'use strict';

    // ==UserScript==
// @name         Horochan VIP Post Hider
// @namespace    https://horochan.ru/
// @version      3.2.1
// @description  Скрытие VIP-постов на horochan.ru с настраиваемым плавающим меню. Через CSS :has() — переживает Svelte и виртуальный скроллинг.
// @author       you
// @match        *://horochan.ru/*
// @match        *://*.horochan.ru/*
// @run-at       document-start
// @grant        none
// ==/UserScript==

(function () {
    'use strict';

    // ============================================================
    //                      ПОСТОЯННЫЕ
    // ============================================================
    const PLACEHOLDER = ' — [Скрыто: VIP-пост, клик чтобы показать]';
    const STORAGE_KEY = 'horochan-vip-hider-settings';

    // BEM-селектор для никнейма и/или трипкода. Реальные классы
    // горочана подтверждены диагностикой: имя — .post-meta__author-name,
    // трипкод — .post-meta__author-trip.
    const NAME_SELECTOR = '.post-meta__author-name, .post-meta__author-trip';

    // ============================================================
    //                     НАСТРОЙКИ
    // ============================================================
    const defaultSettings = {
        fullyHide: false,      // скрывать пост целиком (без плашки)
        onlyNamed: false,      // только VIP с ником/трипкодом
        onlyAnonymous: false,  // только VIP без ника/трипкода (анонимные)
    };

    function loadSettings() {
        try {
            const saved = localStorage.getItem(STORAGE_KEY);
            if (saved) return Object.assign({}, defaultSettings, JSON.parse(saved));
        } catch (e) {}
        return Object.assign({}, defaultSettings);
    }

    function saveSettings(s) {
        try { localStorage.setItem(STORAGE_KEY, JSON.stringify(s)); } catch (e) {}
    }

    let settings = loadSettings();

    // ============================================================
    //                       CSS-СБОРЩИК
    // ============================================================
    function buildHidingCSS() {
        // База: VIP-пост, который ещё не раскрыт пользователем
        let target = 'article.post:has(.post-meta__vip):not(.vip-hider-shown)';
        // Доп. фильтр (взаимоисключающие; UI не даст включить оба разом)
        if (settings.onlyNamed) {
            target += `:has(${NAME_SELECTOR})`;
        } else if (settings.onlyAnonymous) {
            target += `:not(:has(${NAME_SELECTOR}))`;
        }

        if (settings.fullyHide) {
            return `${target} { display: none !important; }`;
        }
        return `
            /* Скрываем потомков <article> рядом с .post-content
               (там лежат attachments — картинки, видео и пр.) */
            ${target} > *:not(.post-content) {
                display: none !important;
            }
            /* Внутри .post-content скрываем всё, кроме заголовка */
            ${target} .post-content > *:not(.post-header) {
                display: none !important;
            }
            /* Плашка-индикатор */
            ${target} .post-header::after {
                content: ${JSON.stringify(PLACEHOLDER)};
                color: #888;
                font-style: italic;
                margin-left: 8px;
                font-size: 13px;
                font-weight: normal;
            }
            ${target} .post-header {
                cursor: pointer;
            }
        `;
    }

    function updateStyles() {
        let style = document.getElementById('vip-hider-styles');
        if (!style) {
            style = document.createElement('style');
            style.id = 'vip-hider-styles';
            (document.head || document.documentElement).appendChild(style);
        }
        style.textContent = buildHidingCSS();
    }

    // ============================================================
    //                      МЕНЮ (UI)
    // ============================================================
    const menuCSS = `
        #vip-hider-menu {
            position: fixed;
            bottom: 16px;
            right: 96px;
            z-index: 99999;
            font-family: 'Comic Sans MS', cursive;
            font-size: 13px;
            color: #ddd;
            user-select: none;
        }
        #vip-hider-toggle {
            width: 60px;
            height: 60px;
            border-radius: 50%;
            background: rgba(40, 40, 40, 0.85);
            border: 1px solid #444;
            color: #ccc;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 28px;
            box-shadow: 0 2px 8px rgba(0,0,0,0.4);
            transition: background 0.15s, transform 0.15s;
            padding: 0;
        }
        #vip-hider-toggle:hover {
            background: rgba(60, 60, 60, 0.95);
            transform: scale(1.05);
        }
        #vip-hider-panel {
            position: absolute;
            bottom: 70px;
            right: 0;
            background: rgba(28, 28, 28, 0.97);
            border: 1px solid #444;
            border-radius: 8px;
            padding: 10px 14px;
            min-width: 240px;
            box-shadow: 0 4px 16px rgba(0,0,0,0.6);
            display: none;
        }
        #vip-hider-panel.visible { display: block; }
        #vip-hider-panel .vip-title {
            font-weight: 600;
            color: #fff;
            margin: 0 0 6px;
            padding-bottom: 6px;
            border-bottom: 1px solid #3a3a3a;
        }
        .vip-row {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding: 8px 0;
            cursor: pointer;
            gap: 12px;
        }
        .vip-row:not(:last-child) {
            border-bottom: 1px solid #2a2a2a;
        }
        .vip-row-label { flex: 1; }
        .vip-switch {
            position: relative;
            display: inline-block;
            width: 36px;
            height: 20px;
            flex-shrink: 0;
        }
        .vip-switch input { opacity: 0; width: 0; height: 0; margin: 0; }
        .vip-track {
            position: absolute;
            inset: 0;
            background: #555;
            border-radius: 20px;
            transition: background 0.2s;
        }
        .vip-track::before {
            content: '';
            position: absolute;
            top: 2px;
            left: 2px;
            width: 16px;
            height: 16px;
            background: #fff;
            border-radius: 50%;
            transition: transform 0.2s;
        }
        .vip-switch input:checked + .vip-track {
            background: #4a8a6a;
        }
        .vip-switch input:checked + .vip-track::before {
            transform: translateX(16px);
        }
    `;

    function injectMenuStyles() {
        if (document.getElementById('vip-hider-menu-styles')) return;
        const style = document.createElement('style');
        style.id = 'vip-hider-menu-styles';
        style.textContent = menuCSS;
        (document.head || document.documentElement).appendChild(style);
    }

    function buildMenu() {
        if (document.getElementById('vip-hider-menu')) return;

        const menu = document.createElement('div');
        menu.id = 'vip-hider-menu';
        menu.innerHTML = `
            <div id="vip-hider-panel">
                <div class="vip-title">Laprosy Vaccine</div>
                <label class="vip-row">
                    <span class="vip-row-label">Скрывать целиком (без плашки)</span>
                    <span class="vip-switch">
                        <input type="checkbox" data-key="fullyHide">
                        <span class="vip-track"></span>
                    </span>
                </label>
                <label class="vip-row">
                    <span class="vip-row-label">Только с ником/трипкодом</span>
                    <span class="vip-switch">
                        <input type="checkbox" data-key="onlyNamed">
                        <span class="vip-track"></span>
                    </span>
                </label>
                <label class="vip-row">
                    <span class="vip-row-label">Только без ника/трипкода</span>
                    <span class="vip-switch">
                        <input type="checkbox" data-key="onlyAnonymous">
                        <span class="vip-track"></span>
                    </span>
                </label>
            </div>
            <button id="vip-hider-toggle" type="button" title="Laprosy Vaccine">💎</button>
        `;
        document.body.appendChild(menu);

        const panel = menu.querySelector('#vip-hider-panel');
        const btn = menu.querySelector('#vip-hider-toggle');

        // Восстанавливаем состояние тумблеров из настроек
        menu.querySelectorAll('input[type="checkbox"]').forEach((input) => {
            const key = input.dataset.key;
            input.checked = !!settings[key];
            input.addEventListener('change', () => {
                settings[key] = input.checked;
                // Взаимное исключение фильтров "только с ником" и "только без ника":
                // включение одного автоматически выключает другой.
                if (input.checked && (key === 'onlyNamed' || key === 'onlyAnonymous')) {
                    const otherKey = key === 'onlyNamed' ? 'onlyAnonymous' : 'onlyNamed';
                    if (settings[otherKey]) {
                        settings[otherKey] = false;
                        const otherInput = menu.querySelector(`input[data-key="${otherKey}"]`);
                        if (otherInput) otherInput.checked = false;
                    }
                }
                saveSettings(settings);
                updateStyles();
            });
        });

        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            panel.classList.toggle('visible');
        });
        // Клик вне меню — закрываем панель
        document.addEventListener('click', (e) => {
            if (!menu.contains(e.target)) panel.classList.remove('visible');
        });
    }

    // ============================================================
    //                  CLICK НА ЗАГОЛОВКЕ
    // ============================================================
    function setupRevealHandler() {
        document.addEventListener('click', (e) => {
            const header = e.target.closest('.post-header');
            if (!header) return;
            const article = header.closest('article.post');
            if (!article) return;
            if (!article.querySelector('.post-meta__vip')) return;
            if (article.classList.contains('vip-hider-shown')) return;
            article.classList.add('vip-hider-shown');
        }, true);
    }

    // ============================================================
    //                        СТАРТ
    // ============================================================
    function initEarly() {
        if (!(document.head || document.body)) return false;
        injectMenuStyles();
        updateStyles();
        return true;
    }

    if (!initEarly()) {
        const obs = new MutationObserver(() => {
            if (initEarly()) obs.disconnect();
        });
        obs.observe(document.documentElement, { childList: true });
    }

    function onReady() {
        buildMenu();
        setupRevealHandler();
    }
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', onReady);
    } else {
        onReady();
    }
})();
})();
